#!/bin/zsh
set -euo pipefail

ROOT_DIR="$(cd "$(dirname "$0")" && pwd)"

API_BASE_URL="${API_BASE_URL:-http://127.0.0.1:10072}"
WEB_BASE_URL="${WEB_BASE_URL:-http://127.0.0.1:10080}"
ALLOWED_ORIGIN="${ALLOWED_ORIGIN:-http://localhost:5173}"
BLOCKED_ORIGIN="${BLOCKED_ORIGIN:-http://malicious.invalid}"
CURL_BIN="${CURL_BIN:-/usr/bin/curl}"
ENV_FILE="${ENV_FILE:-$ROOT_DIR/../.env}"

PASS_COUNT=0
FAIL_COUNT=0

FINANCE_SMOKE_B64=""
MERCHANT_SMOKE_B64=""

usage() {
  cat <<'EOH'
Usage: ./scripts/test_suite.sh <command>

Commands:
  security      Run security smoke (CORS/headers/CSRF/callback)
  release-env   Validate release security env config
  finance       Run finance smoke batches
  merchant      Run merchant module smoke
  all           Run release-env + security + finance + merchant
  help          Show this help

Examples:
  ./scripts/test_suite.sh security
  ENV_FILE=./.env.example ./scripts/test_suite.sh release-env
  API_BASE_URL=http://127.0.0.1:10072 WEB_BASE_URL=http://127.0.0.1:10080 ./scripts/test_suite.sh security
EOH
}

pass() {
  PASS_COUNT=$((PASS_COUNT + 1))
  echo "[PASS] $1"
}

fail() {
  FAIL_COUNT=$((FAIL_COUNT + 1))
  echo "[FAIL] $1"
}

run_cmd_item() {
  local name="$1"
  local cmd="$2"
  local before_fail
  before_fail=$FAIL_COUNT
  echo "===== ${name} ====="
  if eval "$cmd"; then
    if [[ $FAIL_COUNT -gt $before_fail ]]; then
      fail "${name} (has assertion failures)"
    else
      pass "$name"
    fi
  else
    local code=$?
    fail "${name} (exit=${code})"
  fi
  echo
}

run_embedded_script() {
  local name="$1"
  local b64="$2"
  local tmp_dir script_path
  tmp_dir=$(mktemp -d)
  script_path="$tmp_dir/${name}.sh"
  if echo "$b64" | base64 -d > "$script_path" 2>/dev/null; then
    true
  else
    echo "$b64" | base64 -D > "$script_path"
  fi
  chmod +x "$script_path"
  if ! zsh "$script_path"; then
    rm -rf "$tmp_dir"
    return 1
  fi
  rm -rf "$tmp_dir"
}

security_smoke() {
  local tmp_dir hdr_file body_file cookie_jar
  tmp_dir=$(mktemp -d)
  hdr_file="$tmp_dir/headers.txt"
  body_file="$tmp_dir/body.txt"
  cookie_jar="$tmp_dir/cookies.txt"

  cleanup_security_tmp() {
    rm -rf "$tmp_dir"
  }

  require_up() {
    local url="$1"
    if ! "$CURL_BIN" -sS --max-time 3 -o /dev/null "$url"; then
      echo "[FAIL] service unreachable: $url"
      echo "[HINT] set API_BASE_URL / WEB_BASE_URL before running"
      return 1
    fi
  }

  extract_header() {
    local name="$1"
    grep -i "^${name}:" "$hdr_file" | head -n 1 | sed 's/^[^:]*:[[:space:]]*//' | tr -d '\r'
  }

  has_header() {
    local name="$1"
    grep -qi "^${name}:" "$hdr_file"
  }

  get_with_origin() {
    local url="$1"
    local origin="$2"
    "$CURL_BIN" -sS -D "$hdr_file" -o "$body_file" -H "Origin: $origin" "$url" >/dev/null
  }

  post_json() {
    local url="$1"
    local data="$2"
    "$CURL_BIN" -sS -D "$hdr_file" -o "$body_file" -H "Content-Type: application/json" -X POST -d "$data" "$url" >/dev/null
  }

  echo "[INFO] API_BASE_URL=$API_BASE_URL"
  echo "[INFO] WEB_BASE_URL=$WEB_BASE_URL"

  require_up "$API_BASE_URL/api/csrf-token"
  require_up "$WEB_BASE_URL/api/base/nologin/health"

  get_with_origin "$API_BASE_URL/api/csrf-token" "$ALLOWED_ORIGIN"
  local api_allow_origin
  api_allow_origin=$(extract_header "Access-Control-Allow-Origin")
  if [[ "$api_allow_origin" == "$ALLOWED_ORIGIN" ]]; then
    pass "API CORS allows configured origin"
  else
    fail "API CORS allowlist mismatch: got='$api_allow_origin' expect='$ALLOWED_ORIGIN'"
  fi

  get_with_origin "$API_BASE_URL/api/csrf-token" "$BLOCKED_ORIGIN"
  if has_header "Access-Control-Allow-Origin"; then
    fail "API CORS unexpectedly allows blocked origin"
  else
    pass "API CORS blocks unknown origin"
  fi

  get_with_origin "$WEB_BASE_URL/api/base/nologin/health" "$ALLOWED_ORIGIN"
  local web_allow_origin
  web_allow_origin=$(extract_header "Access-Control-Allow-Origin")
  if [[ "$web_allow_origin" == "$ALLOWED_ORIGIN" ]]; then
    pass "Web CORS allows configured origin"
  else
    fail "Web CORS allowlist mismatch: got='$web_allow_origin' expect='$ALLOWED_ORIGIN'"
  fi

  get_with_origin "$API_BASE_URL/api/csrf-token" "$ALLOWED_ORIGIN"
  local h
  for h in "X-Content-Type-Options" "X-Frame-Options" "X-XSS-Protection" "Strict-Transport-Security"; do
    if has_header "$h"; then
      pass "API security header present: $h"
    else
      fail "API security header missing: $h"
    fi
  done

  "$CURL_BIN" -sS -D "$hdr_file" -c "$cookie_jar" -o "$body_file" -H "Origin: $ALLOWED_ORIGIN" "$API_BASE_URL/api/csrf-token" >/dev/null
  local csrf_header csrf_cookie
  csrf_header=$(extract_header "X-CSRF-Token")
  csrf_cookie=$(awk '$6=="CSRF-Token" {print $7; exit}' "$cookie_jar")
  if [[ -n "$csrf_header" && -n "$csrf_cookie" && "$csrf_header" == "$csrf_cookie" ]]; then
    pass "CSRF token header/cookie consistent"
  else
    fail "CSRF token mismatch header='$csrf_header' cookie='$csrf_cookie'"
  fi

  if grep -q 'csrf_token' "$body_file"; then
    pass "CSRF token endpoint returns csrf_token payload"
  else
    fail "CSRF token endpoint payload missing csrf_token"
  fi

  post_json "$API_BASE_URL/api/clientlogs" '{}'
  if grep -q '"code":0' "$body_file"; then
    fail "CSRF-protected POST unexpectedly succeeded without token"
  else
    pass "CSRF-protected POST rejected without token"
  fi

  post_json "$API_BASE_URL/api/callback/pay/test-channel" '{}'
  if grep -qi 'success' "$body_file"; then
    pass "Callback path bypasses CSRF as expected"
  else
    fail "Callback path did not return expected success payload"
  fi

  cleanup_security_tmp
}

release_env_check() {
  if [[ -f "$ENV_FILE" ]]; then
    source "$ENV_FILE"
  fi

  local required
  required=(
    SESSION_AUTH_TOKEN
    SHA256_SALT
    API_SHA256_SALT
    CRYPTO_AUTH_TOKEN
    ALLOWED_CORS_ORIGINS
    PAYMENT_CALLBACK_IPS
  )

  check_non_empty() {
    local key="$1"
    local val="${(P)key:-}"
    if [[ -z "$val" ]]; then
      fail "${key} is empty"
      return
    fi
    pass "${key} is set"
  }

  check_not_default() {
    local key="$1"
    local val="${(P)key:-}"
    if [[ "$val" == DEFAULT_* ]]; then
      fail "${key} uses insecure default value"
      return
    fi
    pass "${key} is not default"
  }

  check_csv_like() {
    local key="$1"
    local val="${(P)key:-}"
    local normalized
    normalized=$(echo "$val" | tr -d '[:space:]')
    if [[ "$normalized" != *","* && "$normalized" != *"/"* && "$normalized" != *"http"* ]]; then
      echo "[WARN] ${key} format may be too narrow: ${val}"
    fi
    pass "${key} format basic check done"
  }

  echo "[INFO] env file: $ENV_FILE"
  local k
  for k in $required; do
    check_non_empty "$k"
  done
  for k in SESSION_AUTH_TOKEN SHA256_SALT API_SHA256_SALT CRYPTO_AUTH_TOKEN; do
    check_not_default "$k"
  done
  check_csv_like ALLOWED_CORS_ORIGINS
  check_csv_like PAYMENT_CALLBACK_IPS
}

run_finance() {
  ensure_admin_login_context || return 1
  run_embedded_script "finance_smoke" "$FINANCE_SMOKE_B64"
}

run_merchant() {
  ensure_admin_login_context || return 1
  run_embedded_script "merchant_smoke" "$MERCHANT_SMOKE_B64"
}

ensure_admin_login_context() {
  if ! command -v redis-cli >/dev/null 2>&1; then
    fail "redis-cli not found; finance/merchant smoke requires redis admin session"
    return 1
  fi

  local admin_json token_key token session check_res k v
  admin_json=$(redis-cli GET LOGIN:USER:USERINFO:admin 2>/dev/null || true)
  token_key=""
  for k in $(redis-cli --raw KEYS 'LOGIN:USER:TOKEN:*' 2>/dev/null || true); do
    v=$(redis-cli --raw GET "$k" 2>/dev/null || true)
    if [[ "$v" == "admin" ]]; then
      token_key="$k"
      break
    fi
  done

  if [[ -z "$admin_json" || -z "$token_key" ]]; then
    fail "missing redis admin login session; login admin first before finance/merchant smoke"
    echo "[HINT] login via backend web first, then rerun finance/merchant"
    return 1
  fi

  token=$(echo "$admin_json" | sed -n 's/.*"token":"\([^"]*\)".*/\1/p')
  session="${token_key#LOGIN:USER:TOKEN:}"
  if [[ -z "$token" || -z "$session" ]]; then
    fail "invalid admin redis session payload; relogin admin and retry"
    return 1
  fi

  check_res=$("$CURL_BIN" -sS "$WEB_BASE_URL/api/fcMerchant/findPage?current=1&pageSize=1" \
    -H "Token: $token" \
    -H "Cookie: aws_session=$session" || true)
  if [[ "$check_res" != *'"code":0'* ]]; then
    fail "admin redis session is stale/unauthorized; relogin admin and retry"
    echo "[HINT] current auth check response: $check_res"
    return 1
  fi

  # Embedded legacy smoke batches may pick the first LOGIN:USER:TOKEN:* key.
  # Keep admin token keys only to avoid selecting stale sessions from old runs.
  for k in $(redis-cli --raw KEYS 'LOGIN:USER:TOKEN:*' 2>/dev/null || true); do
    v=$(redis-cli --raw GET "$k" 2>/dev/null || true)
    if [[ "$v" != "admin" ]]; then
      redis-cli DEL "$k" >/dev/null 2>&1 || true
    fi
  done

  pass "redis admin login session detected"
}

run_all() {
  run_cmd_item "release-env" "release_env_check"
  run_cmd_item "security" "security_smoke"
  run_cmd_item "finance" "run_finance"
  run_cmd_item "merchant" "run_merchant"
}

cmd="${1:-help}"

case "$cmd" in
  security)
    security_smoke
    ;;
  release-env)
    release_env_check
    ;;
  finance)
    run_finance
    ;;
  merchant)
    run_merchant
    ;;
  all)
    run_all
    ;;
  help|-h|--help)
    usage
    exit 0
    ;;
  *)
    echo "Unknown command: $cmd"
    usage
    exit 2
    ;;
esac

echo "[INFO] pass=$PASS_COUNT fail=$FAIL_COUNT"
if [[ $FAIL_COUNT -gt 0 ]]; then
  exit 1
fi

echo "[DONE] test suite passed"
